# test_initialize_modules ----
## Setup ----

data <- FIMS::FIMSFrame(data1)

default_parameters <- create_default_configurations(data = data) |>
  create_default_parameters(data = data) |>
  tidyr::unnest(cols = data)

vonb_parameters <- create_default_configurations(data = data) |>
  tidyr::unnest(cols = data) |>
  dplyr::rows_update(
    tibble::tibble(
      module_name = "Growth",
      module_type = "VonBertalanffy"
    ),
    by = c("module_name")
  ) |>
  create_default_parameters(data = data) |>
  tidyr::unnest(cols = data)

make_vonb_interpolation_sd_rows <- function(parameters) {
  reference_age_1 <- parameters |>
    dplyr::filter(
      module_name == "Growth",
      label == "reference_age_for_length_1"
    ) |>
    dplyr::pull(value)

  reference_age_2 <- parameters |>
    dplyr::filter(
      module_name == "Growth",
      label == "reference_age_for_length_2"
    ) |>
    dplyr::pull(value)

  create_default_parameters_template(n_parameters = 2) |>
    dplyr::mutate(
      module_name = "Growth",
      module_type = "VonBertalanffy",
      label = "length_at_age_sd_at_ref_ages",
      age = c(reference_age_1, reference_age_2),
      value = c(28, 73),
      estimation_type = c("constant", "constant")
    )
}

make_no_local_alk_fleet_context <- function() {
  no_local_alk_data <- data |>
    get_data() |>
    dplyr::filter(
      !(
        name == "fleet1" &
          type %in% c("age-to-length-conversion", "length-bin")
      )
    )

  frame <- FIMS::FIMSFrame(no_local_alk_data)
  parameters <- create_default_configurations(data = frame) |>
    create_default_parameters(data = frame) |>
    tidyr::unnest(cols = data)

  list(
    data = frame,
    parameters = parameters
  )
}

## IO correctness ----
test_that("`initialize_fims()` works with correct inputs", {
  result <- initialize_fims(parameters = default_parameters, data = data)
  #' @description Test that `initialize_fims()` returns a list.
  expect_type(result, "list")
  #' @description Test that `initialize_fims()` returns an output with correct names.
  expect_named(result, c("parameters", "model", "metadata"))
  #' @description Test that `initialize_fims()` returns a list with three elements.
  expect_equal(length(result), 3)
  clear()

  result <- initialize_comp(
    data = data,
    fleet_name = "fleet1",
    type = "AgeComp"
  )

  #' @description Test that `initialize_comp()` works with `AgeComp` type and returns an S4 object.
  expect_type(result, "S4")
  #' @description Test that `initialize_comp()` works with `AgeComp` type and does not produce an error.
  expect_no_error(result[["age_comp_data"]])
  #' @description Test that `initialize_comp()` works with `AgeComp` type and sets `length_comp_data` to NULL.
  expect_null(result[["length_comp_data"]])
  #' @description Test that `initialize_comp()` output contains the correct structure.
  expect_true(
    all(c("age_comp_data", "initialize", "finalize", ".pointer") %in%
      names(result))
  )
  #' @description Test that the age-composition data in the returned object from `initialize_comp()` has the correct values.
  expect_equal(
    result$age_comp_data$toRVector(),
    data |>
      get_data() |>
      dplyr::filter(type == "age_comp", name == "fleet1") |>
      dplyr::mutate(out = value * uncertainty) |>
      dplyr::pull(out)
  )
  clear()

  result <- initialize_comp(
    data = data,
    fleet_name = "fleet1",
    type = "LengthComp"
  )
  #' @description Test that `initialize_fims()` works with `LengthComp` type and returns an S4 object.
  expect_type(result, "S4")
  #' @description Test that `initialize_fims()` works with `LengthComp` type and does not produce an error.
  expect_no_error(result[["length_comp_data"]])
  #' @description Test that `initialize_fims()` works with `LengthComp` type and sets `age_comp_data` to NULL.
  expect_null(result[["age_comp_data"]])
  #' @description Test that `initialize_fims()` output contains the correct structure.
  expect_true(
    all(c("length_comp_data", "initialize", "finalize", ".pointer") %in%
      names(result))
  )
  #' @description Test that the length-composition data in the returned object from `initialize_comp()` has the correct values.
  expect_equal(
    result$length_comp_data$toRVector(),
    data |>
      get_data() |>
      dplyr::filter(type == "length_comp", name == "fleet1") |>
      dplyr::mutate(out = value * uncertainty) |>
      dplyr::pull(out)
  )
  clear()
})

test_that("initialize_growth errors when neither variability path is supplied", {
  parameters <- vonb_parameters |>
    dplyr::filter(
      !(module_name == "Growth" &
          (label == "length_at_age_sd_at_ref_ages" |
             label %in% c(
               "log_sd_length_at_ref_age_1",
               "log_sd_length_at_ref_age_2",
               "log_sd_growth_coefficient_K",
               "logit_corr_length_at_ref_age_1_length_at_ref_age_2",
               "logit_corr_length_at_ref_age_1_k",
               "logit_corr_length_at_ref_age_2_k"
             )))
    )

  #' @description Test that initialize_growth() requires users to supply
  #' either interpolation inputs or a complete delta-method variability block.
  expect_error(
    initialize_growth(
      parameters = parameters,
      data = data
    ),
    regexp = "requires variability inputs for exactly one supported path"
  )
  clear()
})

test_that("initialize_growth accepts interpolation inputs without delta-method inputs", {
  interpolation_rows <- make_vonb_interpolation_sd_rows(vonb_parameters)

  parameters <- vonb_parameters |>
    dplyr::filter(
      !(module_name == "Growth" &
          label %in% c(
            "log_sd_length_at_ref_age_1",
            "log_sd_length_at_ref_age_2",
            "log_sd_growth_coefficient_K",
            "logit_corr_length_at_ref_age_1_length_at_ref_age_2",
            "logit_corr_length_at_ref_age_1_k",
            "logit_corr_length_at_ref_age_2_k"
          ))
    ) |>
    dplyr::bind_rows(interpolation_rows)

  growth <- initialize_growth(
    parameters = parameters,
    data = data
  )

  #' @description Test that initialize_growth() accepts the interpolation
  #' inputs without requiring or silently backfilling the delta-method
  #' variability block.
  expect_equal(growth$length_at_age_sd_at_ref_ages$size(), 2)
  expect_equal(growth$log_sd_length_at_ref_age_1$size(), 0)
  expect_equal(growth$log_sd_length_at_ref_age_2$size(), 0)
  expect_equal(growth$log_sd_growth_coefficient_K$size(), 0)
  expect_equal(growth$logit_corr_length_at_ref_age_1_length_at_ref_age_2$size(), 0)
  expect_equal(growth$logit_corr_length_at_ref_age_1_k$size(), 0)
  expect_equal(growth$logit_corr_length_at_ref_age_2_k$size(), 0)
  clear()
})

test_that("initialize_growth errors when both variability paths are supplied", {
  interpolation_rows <- make_vonb_interpolation_sd_rows(vonb_parameters)

  parameters <- vonb_parameters |>
    dplyr::bind_rows(interpolation_rows)

  #' @description Test that initialize_growth() rejects parameter tables that
  #' supply both interpolation inputs and the full delta-method variability
  #' block at the same time.
  expect_error(
    initialize_growth(
      parameters = parameters,
      data = data
    ),
    regexp = "for the delta-method path, but not both"
  )
  clear()
})

test_that("initialize_growth errors on partial delta-method variability inputs", {
  parameters <- vonb_parameters

  partial_parameters <- parameters |>
    dplyr::filter(
      !(module_name == "Growth" &
          label %in% c(
            "log_sd_length_at_ref_age_2",
            "log_sd_growth_coefficient_K",
            "logit_corr_length_at_ref_age_1_length_at_ref_age_2",
            "logit_corr_length_at_ref_age_1_k",
            "logit_corr_length_at_ref_age_2_k"
          ))
    )

  #' @description Test that initialize_growth() rejects incomplete VonB
  #' delta-method variability input sets.
  expect_error(
    initialize_growth(
      parameters = partial_parameters,
      data = data
    ),
    regexp = "delta-method variability inputs must be supplied as a complete set"
  )
  clear()
})

test_that("initialize_growth accepts complete delta-method variability inputs", {
  parameters <- vonb_parameters

  growth <- initialize_growth(
    parameters = parameters,
    data = data
  )

  #' @description Test that initialize_growth() accepts a complete VonB
  #' delta-method variability block.
  expect_equal(growth$log_sd_length_at_ref_age_1$size(), 1)
  expect_equal(growth$log_sd_length_at_ref_age_2$size(), 1)
  expect_equal(growth$log_sd_growth_coefficient_K$size(), 1)
  expect_equal(growth$logit_corr_length_at_ref_age_1_length_at_ref_age_2$size(), 1)
  expect_equal(growth$logit_corr_length_at_ref_age_1_k$size(), 1)
  expect_equal(growth$logit_corr_length_at_ref_age_2_k$size(), 1)
  clear()
})

## Edge handling ----
test_that("`initialize_fims()` works with edge cases", {
  modified_log_devs <- default_parameters |>
    dplyr::filter(label == "log_devs") |>
    # change first 10 estimation_type for label of log_devs from fixed_effects
    # to constant
    dplyr::mutate(
      estimation_type = dplyr::if_else(
        time <= 11,
        "constant",
        estimation_type
      )
    )

  parameters_multiple_types <- default_parameters |>
    # Remove rows where label is "log_devs" but keep the rows where label is NA
    dplyr::filter(label != "log_devs" | is.na(label)) |>
    dplyr::bind_rows(modified_log_devs)
  init_parm_default <- initialize_fims(parameters = default_parameters, data = data)
  init_parm_multiple_types <- initialize_fims(parameters = parameters_multiple_types, data = data)
  #' @description Test that `initialize_fims()` works with multiple estimation types.
  expect_equal(length(init_parm_multiple_types$parameters$p), length(init_parm_default$parameters$p) - 10)
})

test_that("fleet LengthComp falls back to global bins when no local bins are present", {
  ctx <- make_no_local_alk_fleet_context()
  on.exit({ rm(ctx); gc() }, add = TRUE)

  fleet_module <- initialize_module(
    parameters = ctx$parameters,
    data = ctx$data,
    module_name = "Fleet",
    fleet_name = "fleet1"
  )

  global_lengths <- FIMS::get_lengths(ctx$data)

  #' @description Test that fleet-level n_lengths stays nonzero via global fallback when no local bins exist.
  expect_gt(fleet_module$n_lengths$get(), 0)
  #' @description Test that fleet-level n_lengths equals the global fallback bin count when no local bins exist.
  expect_equal(fleet_module$n_lengths$get(), length(global_lengths))
  #' @description Test that fleet-level lengths equal the global fallback bins when no local bins exist.
  expect_equal(fleet_module$lengths$toRVector(), global_lengths)
  clear()
})

## Error handling ----

test_that("`initialize_fims()` returns correct error messages", {
  #' @description Test that `initialize_fims()` handles missing parameters input correctly.
  expect_error(
    initialize_fims(data = data),
    "The `parameters` argument must be a tibble."
  )
  clear()

  #' @description Test that `initialize_fims()` handles non-list parameters input correctly.
  expect_error(
    initialize_fims(parameters = "not_a_list", data = data),
    "The `parameters` argument must be a tibble."
  )
  clear()

  parameters_no_fleets <- default_parameters |>
    dplyr::filter(!(fleet_name %in% c("fleet1", "survey1")))
  #' @description Test that `initialize_fims()` fails when no fleets are provided.
  expect_error(
    initialize_fims(parameters = parameters_no_fleets, data = data),
    "No fleets found in the provided `parameters`."
  )
  clear()

  #' @description Test that `initialize_comp()` correctly returns error on unknown `fleet_name`.
  expect_error(
    initialize_comp(
      data = data,
      fleet_name = "unknown_fleet",
      type = "AgeComp"
    ),
    "Fleet `unknown_fleet` not found in the data object."
  )
  clear()

  #' @description Test that `initialize_comp()` correctly returns error on unknown `type`.
  expect_error(
    initialize_comp(
      data = data,
      fleet_name = "fleet1",
      type = "unknown"
    ),
    "should be one of"
  )

  clear()

  base_data <- get_data(data)
  fleet1_length_bins <- base_data |>
    dplyr::filter(
      .data[["name"]] == "fleet1",
      .data[["type"]] == "length_comp",
      !is.na(.data[["length"]])
    ) |>
    dplyr::pull(.data[["length"]]) |>
    unique() |>
    sort()
  local_bin_rows <- tibble::tibble(
    type = "length-bin",
    name = "fleet1",
    age = NA_real_,
    length = fleet1_length_bins,
    value = NA_real_,
    unit = base_data |>
      dplyr::filter(
        .data[["name"]] == "fleet1",
        .data[["type"]] == "length_comp"
      ) |>
      dplyr::pull(.data[["unit"]]) |>
      unique() |>
      (\(x) x[[1]])(),
    timing = min(
      base_data |>
        dplyr::filter(
          .data[["name"]] == "fleet1",
          .data[["type"]] == "length_comp"
        ) |>
        dplyr::pull(.data[["timing"]]),
      na.rm = TRUE
    ),
    uncertainty = NA_real_
  )
  local_bin_data <- base_data |>
    dplyr::filter(!(
      .data[["name"]] == "fleet1" &
        .data[["type"]] == "age-to-length-conversion"
    )) |>
    dplyr::bind_rows(local_bin_rows)
  local_bin_frame <- FIMS::FIMSFrame(local_bin_data)

  base_lengthcomp <- initialize_comp(
    data = local_bin_frame,
    fleet_name = "fleet1",
    type = "LengthComp"
  )$length_comp_data$toRVector()
  template_row <- local_bin_data |>
    dplyr::filter(name == "fleet1", type == "length_comp") |>
    dplyr::slice_head(n = 1)
  out_of_bin_length <- max(fleet1_length_bins, na.rm = TRUE) + 100

  bad_row <- template_row |>
    dplyr::mutate(
      length = out_of_bin_length,
      value = 0.25
    )
  bad_frame <- FIMS::FIMSFrame(dplyr::bind_rows(local_bin_data, bad_row))
  #' @description Test that `initialize_comp()` hard-fails when local-bin fleets contain non-missing out-of-bin length_comp rows.
  expect_error(
    initialize_comp(
      data = bad_frame,
      fleet_name = "fleet1",
      type = "LengthComp"
    ),
    "outside its resolved length bins"
  )
  clear()

  missing_row <- template_row |>
    dplyr::mutate(
      length = out_of_bin_length,
      value = -999
    )
  missing_frame <- FIMS::FIMSFrame(dplyr::bind_rows(local_bin_data, missing_row))
  #' @description Test that placeholder (-999) out-of-bin rows are allowed and ignored for local-bin fleets.
  expect_no_error(
    missing_result <- initialize_comp(
      data = missing_frame,
      fleet_name = "fleet1",
      type = "LengthComp"
    )
  )
  expect_equal(missing_result$length_comp_data$toRVector(), base_lengthcomp)
  clear()

  parameters_wrong_type <- default_parameters |>
    dplyr::mutate(
      estimation_type = dplyr::if_else(
        estimation_type == "fixed_effects",
        "fixed.effects",
        estimation_type
      )
    )
  parameters_wrong_type[["parameters"]][["recruitment"]][["BevertonHoltRecruitment.log_devs.estimation_type"]] <- "fixed.effects"
  #' @description Test that `initialize_fims()` correctly returns an error on an unknown estimation_type.
  expect_error(
    initialize_fims(parameters = parameters_wrong_type, data = data),
    "The `estimation_type` must be one of: constant, fixed_effects, and random_effects."
  )
  clear()

  ctx <- make_no_local_alk_fleet_context()
  on.exit({ rm(ctx); gc() }, add = TRUE)
  #' @description Test that fleets on the fixed path hard-fail when n_lengths > 0 but fixed ALK is empty.
  expect_error(
    ctx$parameters |>
      initialize_fims(data = ctx$data) |>
      fit_fims(optimize = FALSE),
    regexp = "no usable age-to-length conversion path"
  )
  clear()
})

